import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, Instagram, Facebook, Youtube } from "lucide-react";
import logo from "../assets/images/logo_final.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // lock background scroll
  useEffect(() => {
    document.body.style.overflow = isOpen ? "hidden" : "auto";
  }, [isOpen]);

  const menuItems = [
    { title: "Home", path: "/" },
    { title: "Academy", path: "/academy" },
    { title: "Pro Services", path: "/pro-services" },
    { title: "Gallery", path: "/gallery" },
    { title: "Our Story", path: "/story" },
    { title: "Connect", path: "/connect" },
  ];

  return (
    <>
      {/* ===== NAVBAR ===== */}
      <nav
        className={`fixed top-0 w-full z-50 transition-all duration-300 ${
          isScrolled
            ? "bg-charcoal/90 backdrop-blur-lg border-b border-gold/30"
            : "bg-charcoal/50 backdrop-blur-md"
        }`}
      >
        <div className="max-w-7xl mx-auto px-6 lg:px-12">
          <div className="flex h-20 items-center justify-between">
            <Link to="/">
              <img src={logo} alt="Logo" className="h-14" />
            </Link>

            {/* Desktop */}
            <div className="hidden md:flex gap-12 items-center flex-1 justify-center">
              {menuItems.map((i) => (
                <Link
                  key={i.path}
                  to={i.path}
                  className="text-xs uppercase tracking-widest text-ivory/70 hover:text-gold transition-colors"
                >
                  {i.title}
                </Link>
              ))}
            </div>

            {/* Desktop Social Icons */}
            <div className="hidden md:flex gap-4 items-center">
              <a
                href="https://www.instagram.com/dod_studio_kn/"
                target="_blank"
                rel="noopener noreferrer"
                className="relative w-10 h-10 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                aria-label="Instagram DOD Studio KN"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                <Instagram
                  size={18}
                  strokeWidth={1.5}
                  className="relative z-10"
                />
              </a>
              <a
                href="https://www.instagram.com/dream_of_dance_studio/"
                target="_blank"
                rel="noopener noreferrer"
                className="relative w-10 h-10 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                aria-label="Instagram Dream of Dance Studio"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                <Instagram
                  size={18}
                  strokeWidth={1.5}
                  className="relative z-10"
                />
              </a>
              <a
                href="https://www.youtube.com/c/VinodKashyapdod"
                target="_blank"
                rel="noopener noreferrer"
                className="relative w-10 h-10 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                aria-label="YouTube"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                <Youtube
                  size={18}
                  strokeWidth={1.5}
                  className="relative z-10"
                />
              </a>
              <a
                href="https://www.facebook.com/dreamofdancestudio/"
                target="_blank"
                rel="noopener noreferrer"
                className="relative w-10 h-10 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                aria-label="Facebook"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                <Facebook
                  size={18}
                  strokeWidth={1.5}
                  className="relative z-10"
                />
              </a>
            </div>

            {/* Mobile Toggle */}
            <button
              className="md:hidden text-gold"
              onClick={() => setIsOpen(true)}
            >
              <Menu size={28} />
            </button>
          </div>
        </div>
      </nav>

      {/* ===== MOBILE OVERLAY (OUTSIDE NAV) ===== */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="fixed inset-0 z-[100] bg-charcoal"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            {/* Close button */}
            <button
              className="absolute top-6 right-6 text-gold"
              onClick={() => setIsOpen(false)}
            >
              <X size={32} />
            </button>

            <div className="flex h-full flex-col items-center justify-center gap-10">
              {menuItems.map((item, i) => (
                <motion.div
                  key={item.path}
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: i * 0.06 }}
                >
                  <Link
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className="text-2xl font-cinzel tracking-widest text-gold hover:text-ivory"
                  >
                    {item.title}
                  </Link>
                </motion.div>
              ))}

              <div className="flex gap-6 pt-12 border-t border-gold/40">
                <a
                  href="https://www.instagram.com/dod_studio_kn/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="relative w-12 h-12 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                  aria-label="Instagram DOD Studio KN"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                  <Instagram
                    size={22}
                    strokeWidth={1.5}
                    className="relative z-10"
                  />
                </a>
                <a
                  href="https://www.instagram.com/dream_of_dance_studio/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="relative w-12 h-12 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                  aria-label="Instagram Dream of Dance Studio"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                  <Instagram
                    size={22}
                    strokeWidth={1.5}
                    className="relative z-10"
                  />
                </a>
                <a
                  href="https://www.youtube.com/c/VinodKashyapdod"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="relative w-12 h-12 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                  aria-label="YouTube"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                  <Youtube
                    size={22}
                    strokeWidth={1.5}
                    className="relative z-10"
                  />
                </a>
                <a
                  href="https://www.facebook.com/dreamofdancestudio/"
                  target="_blank"
                  rel="noopener noreferrer"
                  className="relative w-12 h-12 rounded-full border border-gold/40 flex items-center justify-center text-gold/70 hover:text-gold hover:border-gold transition-all duration-300 group"
                  aria-label="Facebook"
                >
                  <div className="absolute inset-0 bg-gradient-to-r from-gold/10 to-transparent opacity-0 group-hover:opacity-100 transition-all duration-300 rounded-full" />
                  <Facebook
                    size={22}
                    strokeWidth={1.5}
                    className="relative z-10"
                  />
                </a>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Navbar;
